import React from 'react';

import "../styles/CustomParallax.css";

const Parallax = ({ elements, scrollPercentage }) => {
  return (
    <div className="parallax-container">
      {elements.map((element, index) => (
        <ParallaxElement
          key={index}
          imgSrc={element.imgSrc}
          imgOffset={element.imgOffset}
          imgSpeed={element.imgSpeed}
          scrollPercentage={scrollPercentage}
        />
      ))}
    </div>
  );
};

const ParallaxElement = ({ imgSrc, imgOffset, imgSpeed, scrollPercentage }) => {
  const translateX = -((scrollPercentage * imgSpeed) - imgOffset);

  return (
    <div
      className="parallax-element"
      style={{ backgroundImage: `url(${imgSrc})`, transform: `translateX(${translateX}px)` }}
    />
  );
};

export default Parallax;
